/*
 * ADC 精度提升分层框架
 *
 * 设计原则（《C语言接口与实现》ch.3 ADT）：
 * 1. 每层封装一类精度损失来源
 * 2. 层间通过标准化接口交互
 * 3. 调用者不需要知道底层做了多少层优化
 *
 * 适用平台：STM32F407VG @ 168MHz, ADC1, PA0 (CH0)
 * 目标精度：12-bit → 14-bit ENOB (通过 16x over-sampling)
 */

#include <stm32f4xx_hal.h>
#include <stdint.h>
#include <stdbool.h>

#define ADC_OVERSAMPLE_COUNT  16
#define ADC_DMA_BUFFER_SIZE   (ADC_OVERSAMPLE_COUNT * 4)
#define ALPHA_SHIFT           4  /* α = 1/16 for IIR filter */

/* ========== 第一层：模拟前端配置 ==========
 * 采样时间配置 —— 确保采样电容充分充电
 * STM32F4: ADC_CLK = 168MHz, 采样时间 84.5 cycles = 503ns
 * RC 时间常数 ~ 4kΩ × 4.7pF = 19ns, 需要 ~27τ 达到 12-bit 精度
 */
typedef struct {
    uint32_t sampling_time;     /* ADC_SAMPLETIME_xxCYCLES_x */
    uint32_t resolution;        /* ADC_RESOLUTION_xxBIT */
    uint32_t data_align;        /* ADC_DATAALIGN_RIGHT/LEFT */
} adc_analog_config_t;

static const adc_analog_config_t adc_afe_config = {
    .sampling_time = ADC_SAMPLETIME_84CYCLES_5,
    .resolution    = ADC_RESOLUTION_12B,
    .data_align    = ADC_DATAALIGN_RIGHT
};

/* ========== 第二层：过采样 + 平均值 ==========
 * 16x Over-Sampling: 有效位数提升 2 bit (12→14 ENOB)
 * 原理: 随机噪声 RMS 值降低 sqrt(N) 倍, N=16 时噪声降低 4x
 */
static uint32_t adc_oversample_average(uint16_t *buffer, uint8_t count)
{
    uint32_t sum = 0;
    for (uint8_t i = 0; i < count; i++) {
        sum += buffer[i];
    }
    return sum >> 4;  /* 右移 4 位 = 除以 16 */
}

/* ========== 第三层：校准层 ==========
 * 两点校准: 输入 0V 和 VREF+, 计算校准系数
 * 使用 Q16 定点数表示 gain_cal
 */
typedef struct {
    int32_t offset_cal;    /* 零点偏移校准值 */
    int32_t gain_cal;      /* 增益校准系数 (Q16 定点) */
    uint32_t vref_cal;     /* 校准时的 VREF+ 测量值 (mV) */
} adc_calibration_t;

static void adc_two_point_calibrate(uint16_t adc_zero, uint16_t adc_vref,
                                     adc_calibration_t *cal)
{
    cal->offset_cal = -(int32_t)adc_zero;
    int32_t span = (int32_t)adc_vref - (int32_t)adc_zero;
    if (span <= 0) span = 1;
    cal->gain_cal = (4095L * 65536L) / span;
    cal->vref_cal = 3300;
}

static int32_t adc_apply_calibration(int32_t raw, const adc_calibration_t *cal)
{
    int32_t corrected = raw + cal->offset_cal;
    return (int32_t)(((int64_t)corrected * cal->gain_cal) >> 16);
}

/* ========== 第四层：数字滤波层 ==========
 * 一阶 IIR 低通滤波器 (指数移动平均)
 * y[n] = α·x[n] + (1-α)·y[n-1], α = 1/16
 */
typedef struct {
    int32_t prev_filtered;
    bool initialized;
} adc_iir_filter_t;

static int32_t adc_iir_filter_update(int32_t raw_input, adc_iir_filter_t *filt)
{
    if (!filt->initialized) {
        filt->prev_filtered = (int32_t)raw_input << ALPHA_SHIFT;
        filt->initialized = true;
        return raw_input;
    }
    int32_t x_scaled = (int32_t)raw_input << ALPHA_SHIFT;
    int32_t y = (x_scaled + (15 * filt->prev_filtered)) >> ALPHA_SHIFT;
    filt->prev_filtered = y;
    return y;
}

/* ========== 顶层接口 ==========
 * 调用者只需调用此函数, 自动获得高精度采样
 */
int32_t adc_high_precision_read(ADC_HandleTypeDef *hadc,
                                 adc_calibration_t *cal,
                                 adc_iir_filter_t *filter)
{
    uint16_t samples[ADC_OVERSAMPLE_COUNT];
    for (uint8_t i = 0; i < ADC_OVERSAMPLE_COUNT; i++) {
        HAL_ADC_Start(hadc);
        HAL_ADC_PollForConversion(hadc, HAL_MAX_DELAY);
        samples[i] = (uint16_t)HAL_ADC_GetValue(hadc);
    }
    HAL_ADC_Stop(hadc);

    int32_t oversampled = (int32_t)adc_oversample_average(samples, ADC_OVERSAMPLE_COUNT);
    int32_t calibrated = adc_apply_calibration(oversampled, cal);
    int32_t filtered = adc_iir_filter_update(calibrated, filter);

    return filtered;
}

/*
 * DMA + Over-Sampling ADC 采样实现
 *
 * 硬件: STM32F407VG, ADC1_CH0 (PA0)
 * DMA2 Stream0 Channel 0
 * 采样率: ~62.5ksps (1Msps / 16 over-sample)
 * 目标: 12-bit ADC → 14-bit ENOB
 */

#include <stm32f4xx_hal.h>
#include <stdint.h>

#define OVERSAMPLE_RATIO    16      /* 16x over-sampling */
#define OVERSAMPLE_LOG2     4       /* log2(16) = 4 */
#define BUFFER_SAMPLES      64      /* DMA 缓冲区大小 (4 组 over-sample) */
#define GROUP_SIZE          16      /* 每组样本数 */

/* DMA 缓冲区: 存放 ADC 原始采样值 */
static volatile uint16_t adc_dma_buffer[BUFFER_SAMPLES];

/* 采样就绪标志: DMA Half-Transfer 中断设置 */
static volatile bool adc_data_ready = false;

/* ADC 句柄 (全局, 供回调使用) */
extern ADC_HandleTypeDef hadc1;
extern DMA_HandleTypeDef hdma_adc1;

/* ========== ADC + DMA 初始化 ==========
 * 注意: 必须在调用此函数前完成 RCC 时钟使能
 */
void adc_dma_init(void)
{
    __HAL_RCC_ADC1_CLK_ENABLE();
    __HAL_RCC_DMA2_CLK_ENABLE();
    __HAL_RCC_GPIOA_CLK_ENABLE();

    /* GPIO PA0 配置为模拟输入 */
    GPIO_InitTypeDef gpio = {
        .Pin = GPIO_PIN_0,
        .Mode = GPIO_MODE_ANALOG,
        .Pull = GPIO_NOPULL
    };
    HAL_GPIO_Init(GPIOA, &gpio);

    /* ADC 配置: 单通道, 长采样时间 */
    ADC_ChannelConfTypeDef channel = {
        .Channel = ADC_CHANNEL_0,       /* PA0 */
        .Rank = 1,
        .SamplingTime = ADC_SAMPLETIME_84CYCLES_5
    };

    HAL_ADC_Init(&hadc1);
    HAL_ADC_ConfigChannel(&hadc1, &channel);

    /* DMA 配置: 循环模式, Half Word 宽度
     * DMA2 Stream0 Channel 0 对应 ADC1
     * 优先级 HIGH 确保不被 SysTick 抢占 */
    hdma_adc1.Init.Channel = DMA_CHANNEL_0;
    hdma_adc1.Init.Direction = DMA_PERIPH_TO_MEMORY;
    hdma_adc1.Init.PeriphInc = DMA_PINC_DISABLE;
    hdma_adc1.Init.MemInc = DMA_MINC_ENABLE;
    hdma_adc1.Init.PeriphDataAlignment = DMA_PDATAALIGN_HALFWORD;
    hdma_adc1.Init.MemDataAlignment = DMA_MDATAALIGN_HALFWORD;
    hdma_adc1.Init.Mode = DMA_CIRCULAR;
    hdma_adc1.Init.Priority = DMA_PRIORITY_HIGH;
    __HAL_LINKDMA(&hadc1, DMA_Handle, hdma_adc1);

    /* 启动 DMA + ADC 连续转换
     * 注意: HAL_ADC_Start_DMA 内部会自动使能 ADC 连续模式 */
    HAL_ADC_Start_DMA(&hadc1, (uint32_t *)adc_dma_buffer, BUFFER_SAMPLES);
}

/* ========== DMA 传输完成回调 ==========
 * 当 DMA 传输到一半（32 个样本）时触发
 * 这是应用层感知新数据可用的唯一途径 */
void HAL_ADC_ConvHalfCpltCallback(ADC_HandleTypeDef *hadc)
{
    /* 前 32 个样本已就绪, 标记数据可用
     * 注意: 此回调在中断上下文中执行, 不能调用 HAL 阻塞函数 */
    adc_data_ready = true;
}

/* ========== 应用层接口 ==========
 * 获取一次高精度采样值 (16x over-sample 平均)
 * 返回: 0-4095 (校准前), -1 表示数据未就绪 */
static int32_t adc_get_high_precision_sample(void)
{
    if (!adc_data_ready) {
        return -1;
    }
    adc_data_ready = false;

    /* 取前 16 个样本做 over-sampling 平均 */
    uint32_t sum = 0;
    for (int i = 0; i < GROUP_SIZE; i++) {
        sum += adc_dma_buffer[i];
    }

    /* 右移 4 位 = 除以 16
     * 注意: 这里用移位代替除法, 避免 ARM 上的 div 指令 (~50 cycles) */
    return (int32_t)(sum >> OVERSAMPLE_LOG2);
}

/*
 * 陷阱 2 的修复代码：通道切换串扰处理
 *
 * 方法 A: 丢弃第一次读数 —— 最简单但浪费一个采样周期
 * 方法 B: 插入 Dummy Conversion —— 不浪费有效采样
 * 方法 C: 使用注入组同时采样 —— 最佳方案但配置复杂
 */

/* 方法 A: 丢弃第一次读数 */
uint16_t adc_read_discard_first(ADC_HandleTypeDef *hadc, uint32_t channel)
{
    ADC_ChannelConfTypeDef conf = {
        .Channel = channel,
        .Rank = 1,
        .SamplingTime = ADC_SAMPLETIME_84CYCLES_5
    };
    HAL_ADC_ConfigChannel(hadc, &conf);

    /* 第一次转换: 丢弃 */
    HAL_ADC_Start(hadc);
    HAL_ADC_PollForConversion(hadc, HAL_MAX_DELAY);
    (void)HAL_ADC_GetValue(hadc);
    HAL_ADC_Stop(hadc);

    /* 第二次转换: 有效 */
    HAL_ADC_Start(hadc);
    HAL_ADC_PollForConversion(hadc, HAL_MAX_DELAY);
    uint16_t result = HAL_ADC_GetValue(hadc);
    HAL_ADC_Stop(hadc);

    return result;
}

/* 方法 B: 插入 Dummy Conversion (同一通道, 短采样时间) */
uint16_t adc_read_dummy_conv(ADC_HandleTypeDef *hadc, uint32_t channel)
{
    /* Rank 1: Dummy - 短采样时间, 清空前一个通道的残留电荷 */
    ADC_ChannelConfTypeDef dummy = {
        .Channel = channel,
        .Rank = 1,
        .SamplingTime = ADC_SAMPLETIME_3CYCLES_5
    };
    /* Rank 2: Real - 长采样时间, 真正采样 */
    ADC_ChannelConfTypeDef real = {
        .Channel = channel,
        .Rank = 2,
        .SamplingTime = ADC_SAMPLETIME_84CYCLES_5
    };

    HAL_ADC_ConfigChannel(hadc, &dummy);
    HAL_ADC_ConfigChannel(hadc, &real);

    HAL_ADC_Start(hadc);
    HAL_ADC_PollForConversion(hadc, HAL_MAX_DELAY);
    uint16_t result = HAL_ADC_GetValue(hadc);  /* Rank 2 的结果 */
    HAL_ADC_Stop(hadc);

    return result;
}

/*
 * 重构示范：从 Long Function 到分层架构
 *
 * 《重构》ch.1 坏味道：
 * - Long Function (过长函数): adc_read_raw() 超过 80 行
 * - Feature Envy (依恋情结): adc_read_raw() 对 adc_calibrate() 的内部数据
 *   结构了解过多
 * - Data Clumps (数据泥团): 校准系数、滤波状态、采样参数散落在各处
 *
 * 《UNIX编程艺术》ch.3 规则 of 分离：
 * "Make each program do one thing well." — 每个函数只做一件事
 */

/* ===== 重构前：一坨函数 (80+ 行) ===== */

/* BAD: 这个函数做了太多事 */
int32_t adc_read_raw(ADC_HandleTypeDef *hadc, uint32_t channel,
                     adc_calibration_t *cal, adc_iir_filter_t *filt)
{
    /* 1. 配置通道 */
    ADC_ChannelConfTypeDef conf = {.Channel = channel, .Rank = 1,
                                   .SamplingTime = ADC_SAMPLETIME_84CYCLES_5};
    HAL_ADC_ConfigChannel(hadc, &conf);

    /* 2. 过采样 16 次 */
    uint32_t sum = 0;
    for (int i = 0; i < 16; i++) {
        HAL_ADC_Start(hadc);
        HAL_ADC_PollForConversion(hadc, HAL_MAX_DELAY);
        sum += HAL_ADC_GetValue(hadc);
    }
    HAL_ADC_Stop(hadc);
    int32_t avg = sum >> 4;

    /* 3. 校准 */
    int32_t corrected = avg + cal->offset_cal;
    corrected = (corrected * cal->gain_cal) >> 16;

    /* 4. IIR 滤波 */
    int32_t filtered;
    if (!filt->initialized) {
        filt->prev_filtered = corrected << 4;
        filt->initialized = true;
        filtered = corrected;
    } else {
        filtered = ((corrected << 4) + 15 * filt->prev_filtered) >> 4;
        filt->prev_filtered = filtered;
    }

    return filtered;
}

/* ===== 重构后：分层函数 (每段 < 15 行) ===== */

/* Layer 1: 模拟前端 — 单次原始采样 */
static uint16_t adc_sample_once(ADC_HandleTypeDef *hadc, uint32_t channel)
{
    ADC_ChannelConfTypeDef conf = {
        .Channel = channel,
        .Rank = 1,
        .SamplingTime = ADC_SAMPLETIME_84CYCLES_5
    };
    HAL_ADC_ConfigChannel(hadc, &conf);

    HAL_ADC_Start(hadc);
    HAL_ADC_PollForConversion(hadc, HAL_MAX_DELAY);
    uint16_t result = HAL_ADC_GetValue(hadc);
    HAL_ADC_Stop(hadc);

    return result;
}

/* Layer 2: 采样策略 — 过采样平均 */
static int32_t adc_oversample(ADC_HandleTypeDef *hadc, uint32_t channel,
                               uint8_t ratio_log2)
{
    uint32_t sum = 0;
    uint8_t count = 1 << ratio_log2;  /* 2^4 = 16 */

    for (uint8_t i = 0; i < count; i++) {
        sum += adc_sample_once(hadc, channel);
    }

    return (int32_t)(sum >> ratio_log2);
}

/* Layer 3: 校准 — 修正系统误差 */
static int32_t adc_do_calibrate(int32_t raw, const adc_calibration_t *cal)
{
    int32_t corrected = raw + cal->offset_cal;
    return (int32_t)(((int64_t)corrected * cal->gain_cal) >> 16);
}

/* Layer 4: 数字滤波 — 抑制随机噪声 */
static int32_t adc_do_filter(int32_t raw, adc_iir_filter_t *filt,
                              uint8_t alpha_shift)
{
    if (!filt->initialized) {
        filt->prev_filtered = raw << alpha_shift;
        filt->initialized = true;
        return raw;
    }

    int32_t y = ((raw << alpha_shift) + (15 * filt->prev_filtered))
                 >> alpha_shift;
    filt->prev_filtered = y;
    return y;
}

/* Top-level: 编排各层，不关心每层的具体实现 */
int32_t adc_read_high_precision(ADC_HandleTypeDef *hadc, uint32_t channel,
                                 adc_calibration_t *cal,
                                 adc_iir_filter_t *filt)
{
    /* 1. 过采样 (16x → +2 bit ENOB) */
    int32_t oversampled = adc_oversample(hadc, channel, 4);

    /* 2. 校准修正 */
    int32_t calibrated = adc_do_calibrate(oversampled, cal);

    /* 3. IIR 滤波 (α = 1/16) */
    int32_t filtered = adc_do_filter(calibrated, filt, 4);

    return filtered;
}
